import json

l2_logs = l2_job.logs()
l2_catalog_url = extract_catalog_url_from_job_logs(l2_logs)
print(f"{l2_catalog_url=}")
l2_catalog = Catalog.from_file(l2_catalog_url)
l2_catalog.set_self_href(l2_catalog_url)
l2_catalog
